In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a basic example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/stat.h>

int main() {
    int fd[2];  // File descriptor for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        std::cerr << "Pipe creation failed\n";
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed\n";
        close(fd[0]);
        close(fd[1]);
        return 1;
    } else if (pid == 0) {  // Child process
        // Close unused ends of the pipe
        close(fd[1]);  // Close write end

        // Redirect stdin and stdout to the read end of the pipe
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Close the pipe again to avoid leaks
        close(fd[0]);

        // Execute a command (e.g., "cat")
        execlp("cat", "cat", (char *)0);
        std::cerr << "Exec failed\n";
        _exit(1);
    } else {  // Parent process
        // Close the read end of the pipe
        close(fd[0]);

        // Write something to the child process's stdin
        const char *message = "Hello, child process!";
        write(fd[1], message, strlen(message));

        // Close the write end of the pipe
        close(fd[1]);

        // Wait for the child process to finish
        wait(NULL);

        std::cout << "Message sent to child process: " << message << std::endl;
    }

    return 0;
}
```

### Explanation:
1. **Pipe Creation**: A pipe is created using `pipe(fd)`. This creates a pair of file descriptors (`fd[0]` for reading, `fd[1]` for writing).

2. **Forking**: `fork()` creates a child process. The parent and child processes will share the same file descriptors, but they will operate independently.

